import React, { useEffect, useState } from 'react';
import { BrowserRouter as Router, Route, Routes, Navigate } from 'react-router-dom';
import Login from './Login';
import Callback from './Callback';
import Dashboard from './Dashboard';
import { AuthProvider, useAuth } from './AuthContext';

function PrivateRoute({ children }) {
  const { isAuthenticated } = useAuth();
  return isAuthenticated ? children : <Navigate to="/login" />;
}

function App() {
  return (
    <Router>
      <AuthProvider>
        <Routes>
          <Route path="/login" element={<Login />} />
          <Route path="/callback" element={<Callback />} />
          <Route
            path="/dashboard"
            element={
              <PrivateRoute>
                <Dashboard />
              </PrivateRoute>
            }
          />
          <Route path="/" element={<Navigate to="/dashboard" />} />
        </Routes>
      </AuthProvider>
    </Router>
  );
}

export default App;

// AuthContext.js
import React, { createContext, useContext, useState, useEffect } from 'react';

const AuthContext = createContext();

export function useAuth() {
  return useContext(AuthContext);
}

export function AuthProvider({ children }) {
  const [accessToken, setAccessToken] = useState(null);
  const [tokenType, setTokenType] = useState(null);
  const [expiresIn, setExpiresIn] = useState(null);
  const [expiresAt, setExpiresAt] = useState(null);
  const [isAuthenticated, setIsAuthenticated] = useState(false);

  useEffect(() => {
    const storedToken = localStorage.getItem('access_token');
    const storedExpiresAt = localStorage.getItem('expires_at');
    
    if (storedToken && storedExpiresAt) {
      const expirationTime = parseInt(storedExpiresAt, 10);
      if (Date.now() < expirationTime) {
        setAccessToken(storedToken);
        setExpiresAt(expirationTime);
        setIsAuthenticated(true);
        setTokenType(localStorage.getItem('token_type') || 'Bearer');
      } else {
        logout();
      }
    }
  }, []);

  useEffect(() => {
    if (expiresAt) {
      const timeout = expiresAt - Date.now();
      if (timeout > 0) {
        const timer = setTimeout(() => {
          logout();
        }, timeout);
        return () => clearTimeout(timer);
      }
    }
  }, [expiresAt]);

  const login = (token, type, expires) => {
    const expirationTime = Date.now() + expires * 1000;
    
    setAccessToken(token);
    setTokenType(type);
    setExpiresIn(expires);
    setExpiresAt(expirationTime);
    setIsAuthenticated(true);

    localStorage.setItem('access_token', token);
    localStorage.setItem('token_type', type);
    localStorage.setItem('expires_at', expirationTime.toString());
  };

  const logout = () => {
    setAccessToken(null);
    setTokenType(null);
    setExpiresIn(null);
    setExpiresAt(null);
    setIsAuthenticated(false);

    localStorage.removeItem('access_token');
    localStorage.removeItem('token_type');
    localStorage.removeItem('expires_at');
  };

  const getAuthHeader = () => {
    return `${tokenType || 'Bearer'} ${accessToken}`;
  };

  const value = {
    accessToken,
    tokenType,
    expiresIn,
    isAuthenticated,
    login,
    logout,
    getAuthHeader
  };

  return <AuthContext.Provider value={value}>{children}</AuthContext.Provider>;
}

