export const oauthConfig = {
  authorizationEndpoint: 'https://your-auth-server.com/oauth/authorize',
  clientId: 'your-client-id',
  redirectUri: window.location.origin + '/callback',
  scope: 'read write',
  state: null
};

export function generateState() {
  const array = new Uint8Array(32);
  window.crypto.getRandomValues(array);
  return Array.from(array, byte => byte.toString(16).padStart(2, '0')).join('');
}

// Login.js
import React, { useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import { useAuth } from './AuthContext';
import { oauthConfig, generateState } from './config';

function Login() {
  const navigate = useNavigate();
  const { isAuthenticated } = useAuth();

  useEffect(() => {
    if (isAuthenticated) {
      navigate('/dashboard');
    }
  }, [isAuthenticated, navigate]);

  const handleLogin = () => {
    const state = generateState();
    sessionStorage.setItem('oauth_state', state);

    const params = new URLSearchParams({
      response_type: 'token',
      client_id: oauthConfig.clientId,
      redirect_uri: oauthConfig.redirectUri,
      scope: oauthConfig.scope,
      state: state
    });

    const authUrl = `${oauthConfig.authorizationEndpoint}?${params.toString()}`;
    window.location.href = authUrl;
  };

  return (
    <div style={{ padding: '50px', textAlign: 'center' }}>
      <h1>OAuth 2.0 Implicit Flow Login</h1>
      <p>Click the button below to authenticate</p>
      <button
        onClick={handleLogin}
        style={{
          padding: '15px 30px',
          fontSize: '16px',
          backgroundColor: '#007bff',
          color: 'white',
          border: 'none',
          borderRadius: '5px',
          cursor: 'pointer'
        }}
      >
        Login with OAuth
      </button>
    </div>
  );
}

export default Login;

// Callback.js
import React, { useEffect, useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { useAuth } from './AuthContext';

function Callback() {
  const navigate = useNavigate();
  const { login } = useAuth();
  const [error, setError] = useState(null);

  useEffect(() => {
    const parseFragment = () => {
      const hash = window.location.hash.substring(1);
      
      if (!hash) {
        setError('No hash fragment found in URL');
        return;
      }

      const params = new URLSearchParams(hash);
      
      const accessToken = params.get('access_token');
      const tokenType = params.get('token_type');
      const expiresIn = params.get('expires_in');
      const state = params.get('state');
      const errorParam = params.get('error');
      const errorDescription = params.get('error_description');

      if (errorParam) {
        setError(`OAuth Error: ${errorParam} - ${errorDescription || 'No description'}`);
        return;
      }

      const storedState = sessionStorage.getItem('oauth_state');
      
      if (state !== storedState) {
        setError('State mismatch - possible CSRF attack');
        sessionStorage.removeItem('oauth_state');
        return;
      }

      sessionStorage.removeItem('oauth_state');

      if (!accessToken) {
        setError('No access token received');
        return;
      }

      const expires = parseInt(expiresIn, 10) || 3600;
      
      login(accessToken, tokenType || 'Bearer', expires);

      window.history.replaceState({}, document.title, window.location.pathname);
      
      navigate('/dashboard');
    };

    parseFragment();
  }, [login, navigate]);

  if (error) {
    return (
      <div style={{ padding: '50px', textAlign: 'center' }}>
        <h2>Authentication Error</h2>
        <p style={{ color: 'red' }}>{error}</p>
        <button
          onClick={() => navigate('/login')}
          style={{
            padding: '10px 20px',
            fontSize: '14px',
            backgroundColor: '#007bff',
            color: 'white',
            border: 'none',
            borderRadius: '5px',
            cursor: 'pointer',
            marginTop: '20px'
          }}
        >
          Back to Login
        </button>
      </div>
    );
  }

  return (
    <div style={{ padding: '50px', textAlign: 'center' }}>
      <h2>Processing authentication...</h2>
      <p>Please wait while we complete your login.</p>
    </div>
  );
}

export default Callback;

// Dashboard.js
import React, { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import { useAuth } from './AuthContext';

function Dashboard() {
  const navigate = useNavigate();
  const { logout, accessToken, getAuthHeader, expiresIn } = useAuth();
  const [userData, setUserData] = useState(null);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState(null);

  const handleLogout = () => {
    logout();
    navigate('/login');
  };

  const fetchUserData = async () => {
    setLoading(true);
    setError(null);
    
    try {
      const response = await fetch('https://your-api.com/user', {
        headers: {
          'Authorization': getAuthHeader(),
          'Content-Type': 'application/json'
        }
      });

      if (!response.ok) {
        throw new Error(`HTTP error! status: ${response.status}`);
      }

      const data = await response.json();
      setUserData(data);
    } catch (err) {
      setError(err.message);
    } finally {
      setLoading(false);
    }
  };

  return (
    <div style={{ padding: '50px' }}>
      <h1>Dashboard</h1>
      <div style={{ marginBottom: '20px' }}>
        <p><strong>Access Token:</strong> {accessToken.substring(0, 20)}...</p>
        <p><strong>Token Type:</strong> Bearer</p>
        <p><strong>Expires In:</strong> {expiresIn} seconds</p>
      </div>

      <div style={{ marginBottom: '20px' }}>
        <button
          onClick={fetchUserData}
          disabled={loading}
          style={{
            padding: '10px 20px',
            fontSize: '14px',
            backgroundColor: '#28a745',
            color: 'white',
            border: 'none',
            borderRadius: '5px',
            cursor: 'pointer',
            marginRight: '10px'
          }}
        >
          {loading ? 'Loading...' : 'Fetch User Data'}
        </button>

        <button
          onClick={handleLogout}
          style={{
            padding: '10px 20px',
            fontSize: '14px',
            backgroundColor: '#dc3545',
            color: 'white',
            border: 'none',
            borderRadius: '5px',
            cursor: 'pointer'
          }}
        >
          Logout
        </button>
      </div>

      {error && (
        <div style={{ padding: '10px', backgroundColor: '#f8d7da', color: '#721c24', borderRadius: '5px', marginBottom: '20px' }}>
          Error: {error}
        </div>
      )}

      {userData && (
        <div style={{ padding: '20px', backgroundColor: '#f8f9fa', borderRadius: '5px' }}>
          <h3>User Data:</h3>
          <pre>{JSON.stringify(userData, null, 2)}</pre>
        </div>
      )}
    </div>
  );
}

export default Dashboard;

